import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"34. Planned And Unplanned Absences","description":"","frontmatter":{"title":"34. Planned And Unplanned Absences","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","staffing","workload","classifications"]},"headers":[],"relativePath":"ebas/mspp/workforce-management/34-planned-and-unplanned-absences.md","filePath":"ebas/mspp/workforce-management/34-planned-and-unplanned-absences.md"}'),s={name:"ebas/mspp/workforce-management/34-planned-and-unplanned-absences.md"};function r(i,e,l,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_34-planned-and-unplanned-absences" tabindex="-1">34. Planned And Unplanned Absences <a class="header-anchor" href="#_34-planned-and-unplanned-absences" aria-label="Permalink to &quot;34. Planned And Unplanned Absences&quot;">​</a></h1><p><strong>34.1</strong> Purpose In order to maintain safe staffing and workload levels and appropriate clinical standards, the Employer will Backfill an Absence or, where that is not possible, prioritise work in accordance with this clause.</p><p><strong>34.2</strong> Definitions In this clause 34:</p><p><strong>a.</strong> Backfill means the replacement of an absent Employee at the same classification and time fraction or, where the replacement Employee is classified at a higher grade than the absent Employee, the replacement Employee’s higher rate.</p><p><strong>b.</strong> Absence includes any type of leave approved by the Employer or WorkCover, either separately or in combination.</p><p><strong>c.</strong> Planned Absence is any Absence of an Employee where it is known in advance it will be for two (2) or more calendar weeks.</p><p><strong>d.</strong> Unplanned Absence is any Absence of an Employee, where:</p><p><strong>(i)</strong> In the case of a shift worker or rostered weekend worker under clause 34.4, the Absence was not known in advance, or</p><p><strong>(ii)</strong> In the case of all other Employees under clause 34.5, it was not known in advance it would be for two (2) or more calendar weeks.</p><p><strong>(iii)</strong> Examples of an Unplanned Absence may include personal leave, resignation or termination of employment resulting in a vacancy or late approved leave.</p><p><strong>34.3</strong> Replacement of staff on Planned Absence</p><p><strong>a.</strong> The Employer will Backfill a Planned Absence from the first day of the absence except as provided at 34.3b below.</p><p><strong>b.</strong> Where, despite best endeavours, the Employer is unable to Backfill a period of leave because a suitably experienced and qualified Employee is unavailable, the work will be prioritised under clause 34.7 below.</p><p><strong>34.4</strong> Unplanned Absences – shift workers and rostered weekend workers Where a shift worker or rostered weekend worker is on an unplanned absence, the Employer will backfill the absent Employee for the duration of the absence save that:</p><p><strong>a.</strong> An Employee who is rostered on-call will not be recalled to fill an unplanned absence unless:</p><p><strong>(i)</strong> the absence is advised after 4.00pm on the day preceding the absence; and</p><p><strong>(ii)</strong> another replacement Employee is not available.</p><p><strong>b.</strong> Where:</p><p><strong>(i)</strong> an unplanned absence is known by the Employer by 4.00pm on the day preceding the absence, and</p><p><strong>(ii)</strong> the absence remains unfilled after all endeavours to replace the absent Employee have been exhausted, the rostered on-call person can be recalled to fill the absence as a matter of last resort.</p><p><strong>34.5</strong> Unplanned Absences - All other Employees</p><p><strong>a.</strong> The Employer will Backfill an Unplanned Absence of two weeks or more.</p><p><strong>b.</strong> Where, despite best endeavours, the Employer is unable to Backfill a period of leave because a suitably experienced and qualified Employee is unavailable, the work will be prioritised under clause 34.7 below.</p><p><strong>34.6</strong> Backfill with existing staff where reasonable The Employer will Backfill by offering existing part time staff and, where necessary, casual staff (which may include bank staff) additional shifts in the first instance.</p><p><strong>34.7</strong> Non-backfilled absences – Work prioritisation</p><p><strong>a.</strong> Where either a Planned or Unplanned Absence is not Backfilled, the Employer will immediately prioritise work to ensure:</p><p><strong>(i)</strong> workloads for other Employees who may be asked to perform the duties of the absent Employee are adjusted by reducing their usual duties; or</p><p><strong>(ii)</strong> the work of the absent Employee is not required to be undertaken by any Employee;</p><p><strong>(iii)</strong> other Employees will not unreasonably be required to work overtime to complete their own work and the work of the absent Employee.</p><p><strong>b.</strong> Prioritised work arrangements made under subclause 34.7a shall be provided in writing to Employees in the service/department of the absent Employee and available for inspection by the Union upon request.</p><p><strong>c.</strong> If overtime is worked, the provisions of <a href="/eba/ebas/mspp/hours-of-work/59-overtime.html">clause 59</a> – Overtime will apply.</p><p><strong>d.</strong> Employers will employ adequate relief Employees or obtain an appropriate replacement scientist or pharmacist from the Public Health Sector Relief Bank or equivalent (see 34.9 below).</p><p><strong>e.</strong> An absent Employee will, on return to work, receive appropriate support to enable them to complete work not done in their absence and is still required to be done.</p><p><strong>34.8</strong> Relevant Information</p><p><strong>a.</strong> The matters in this clause are directly relevant to workload and the Employer will provide information to the Workplace Implementation and Compliance Committee as required by subclause 17.10 of this Agreement</p><p><strong>b.</strong> In the event that a WICC has not been established and there is a dispute with respect to this clause, the Employer will provide relevant information that will provide clarification of the workload or staffing issues. Information that could be relevant is outlined at <a href="/eba/ebas/mspp/union-rights/17-union-rights.html">clause 17.10c</a>.</p><p><strong>34.9</strong> Banks</p><p><strong>a.</strong> Employers recognise adequate relief staff may be needed, or appropriate staff from public health sector relief bank/s utilised, in the event they are established, to backfill positions in accordance with this clause, other than in circumstances where existing staff (part-time and casual) are offered and accept additional hours/shifts for this purpose.</p><p><strong>b.</strong> Employers and the Union will discuss arrangements for building increased relief staff size, which could include sector-wide or internal relief bank/s.</p><p><strong>34.10</strong> Dispute Settlement In the event of a dispute arising over the provisions of this clause, either party may choose to have the dispute resolved under <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> – Disputes Settling Procedure.</p><p>Plain language terms: absence management.</p>',41)])])}const b=n(s,[["render",r]]);export{m as __pageData,b as default};
